"use strict";(self.webpackChunkronamosa_github_io=self.webpackChunkronamosa_github_io||[]).push([[48340],{14489:e=>{e.exports=JSON.parse('{"permalink":"/blog/2022/01/05/Control-the-Narrative","editUrl":"https://github.com/ronamosa/ronamosa.github.io/edit/main/website/blog/2022-01-05-Control-the-Narrative.md","source":"@site/blog/2022-01-05-Control-the-Narrative.md","title":"Control the narrative","description":"This phrase and topic can be seen in a few ways, but I think using this","date":"2022-01-05T00:00:00.000Z","tags":[{"inline":true,"label":"personal","permalink":"/blog/tags/personal"}],"readingTime":2.67,"hasTruncateMarker":true,"authors":[{"name":"Ron Amosa","title":"Platform Security Engineer @ Salesforce U.S.","url":"https://github.com/ronamosa","imageURL":"https://github.com/ronamosa.png","key":null,"page":null}],"frontMatter":{"title":"Control the narrative","author":"Ron Amosa","author_title":"Platform Security Engineer @ Salesforce U.S.","author_url":"https://github.com/ronamosa","author_image_url":"https://github.com/ronamosa.png","tags":["personal"]},"unlisted":false,"prevItem":{"title":"Historical Amnesia.","permalink":"/blog/2022/01/07/Historical-Amnesia"},"nextItem":{"title":"2022. Remember Death.","permalink":"/blog/2022/01/03/Memento-Mori"}}')},28453:(e,t,n)=>{n.d(t,{R:()=>s,x:()=>i});var o=n(96540);const a={},r=o.createContext(a);function s(e){const t=o.useContext(r);return o.useMemo((function(){return"function"==typeof e?e(t):{...t,...e}}),[t,e])}function i(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(a):e.components||a:s(e.components),o.createElement(r.Provider,{value:t},e.children)}},82775:(e,t,n)=>{n.r(t),n.d(t,{assets:()=>h,contentTitle:()=>i,default:()=>c,frontMatter:()=>s,metadata:()=>o,toc:()=>l});var o=n(14489),a=n(74848),r=n(28453);const s={title:"Control the narrative",author:"Ron Amosa",author_title:"Platform Security Engineer @ Salesforce U.S.",author_url:"https://github.com/ronamosa",author_image_url:"https://github.com/ronamosa.png",tags:["personal"]},i=void 0,h={authorsImageUrls:[void 0]},l=[];function u(e){const t={blockquote:"blockquote",p:"p",...(0,r.R)(),...e.components};return(0,a.jsxs)(a.Fragment,{children:[(0,a.jsx)(t.p,{children:"This phrase and topic can be seen in a few ways, but I think using this\nphrase instead of making another one up can serve to hijack whatever\ninfluence this one has for the one I'm about to write about."}),"\n",(0,a.jsx)(t.p,{children:"I subject myself to a myriad of inputs, from newspapers, social media,\nblog posts and research papers to discord and slack chats, text messages\nfrom people and then talking to actual in-real-life people and getting\ntheir thoughts and opinions on all of the things as well."}),"\n",(0,a.jsx)(t.p,{children:'I say "subject myself" because, after much thought and reflection, I\'ve\ndecided that this is something that I do to myself in that I allow it to\nhappen. I have control over opening up twitter, reading an instagram\npost or newspaper article.'}),"\n",(0,a.jsx)(t.p,{children:"I don't have to do any of these things. That I've conditioned myself,\nabsent-mindedly or whatever, over the years to repeat these things says\nmore about my being present or deliberate about how I conduct my life or\nactively seek things out with intent, than it does about the fact this\nis \"just how the things are\", that this is normal, it's no big deal."}),"\n",(0,a.jsx)(t.p,{children:'So action begets results, in my opinion anyway. And you are the product\nor result of your "things"- i.e. environment, choices and serendipity. And among\nyour "things" are the those which you can control, and those that you\ncan\'t.'}),"\n",(0,a.jsx)(t.p,{children:'The headline reads "control the narrative", and the narrative I\'m\ntalking about has been described as "the story you tell yourself" by our self-help friends, the\n"self talk", your "inner voice"- yes all of that. And in the same way\nvarious entities have used "control the narrative" to mean lie and\nbullshit your way around the place to get away with evil shit, the same\nmechanism is available, hopefully for "good", for yourself.'}),"\n",(0,a.jsxs)(t.blockquote,{children:["\n",(0,a.jsx)(t.p,{children:"How do I control the narrative?"}),"\n"]}),"\n",(0,a.jsx)(t.p,{children:"Choose what you consume. Sounds easy right? It isn't."}),"\n",(0,a.jsx)(t.p,{children:"Do you really need to follow that person on Twitter? Why are you\nscrolling through Instagram for 2 hours every day? If you get upset at a\nnewspaper story of racist people being racist, do you really need to\nread it? Does reading it increase your understanding of racism and help\ndefeat it or does it just make you angry?"}),"\n",(0,a.jsx)(t.p,{children:"Ask yourself these things then take action. I like listening to cheesy\nfeel-good country songs cos they make me feel good- do I think the world\nis all sushine and rainbows when I'm feeling good? No, of course not-\neverything's on fire (jokes, sort of). But getting angry about something\nI can't do anything about (the world) is no use to anyonej, especially\nme."}),"\n",(0,a.jsxs)(t.blockquote,{children:["\n",(0,a.jsx)(t.p,{children:"Should I not care about or pay attention to the shit then?"}),"\n"]}),"\n",(0,a.jsx)(t.p,{children:"Nobody's saying that. Care, sure. Care by being a better person\nyourself. Start there. Pay attention? if you didn't know before, sure,\npay attention. If you already know and think paying attention will\nprovide a constructive outcome in your life, sure. Otherwise, no, pay\nattention to yourself and the work you need to do to be a better person."}),"\n",(0,a.jsx)(t.p,{children:"So yeah, that's it. This was just something I've been thinking about."})]})}function c(e={}){const{wrapper:t}={...(0,r.R)(),...e.components};return t?(0,a.jsx)(t,{...e,children:(0,a.jsx)(u,{...e})}):u(e)}}}]);